--
-- Remove Schema Binding option from [SJob].[JobFinance]
--
GO
CREATE OR ALTER VIEW [SJob].[JobFinance]
AS 
SELECT	j.ID,
		TransactionTotals.Net AS InvoicedValue,
		CONVERT(DECIMAL(9, 2), ROUND(j.AgreedFee - TransactionTotals.Net, 2)) AS OutstandingFee
FROM	SJob.Jobs j
OUTER APPLY	
(
	SELECT	SUM(tc.Net * CASE WHEN tt.IsNegated = 1 THEN -1 ELSE 1 END) AS Net
	FROM	SFin.Transactions t
	JOIN	SFin.TransactionTypes tt ON (tt.ID = t.TransactionTypeID)
	JOIN	SFin.TransactionCalculations tc ON (t.ID = tc.ID)
	WHERE	(t.RowStatus NOT IN (0, 254))
		AND	(t.JobID = j.ID)
		AND	(tt.IsBank = 0)
) AS TransactionTotals
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SFin].[tvf_AccountTransactions]
--
GO
CREATE OR ALTER FUNCTION [SFin].[tvf_AccountTransactions] 
(
    @UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
AS
RETURN 
SELECT  t.ID,
        t.RowStatus,
        t.RowVersion,
        t.Guid,
        t.Number,
		t.Date,
		a.Name AS Account,
		tt.Name AS TransactionType,
		tc.RealNet AS Net,
		tc.RealVat AS Vat,
		tc.RealGross AS Gross,
		tc.RealOutstanding AS Outstanding
FROM    SFin.Transactions t
JOIN	SFin.TransactionCalculations tc ON (tc.ID = t.ID)
JOIN    SFin.TransactionTypes tt ON (tt.ID = t.TransactionTypeID)
JOIN	SCrm.Accounts a ON (a.ID = t.AccountID)
WHERE   (t.RowStatus  NOT IN (0, 254))
	AND	(t.Id > 0)
	AND	(a.Guid = @ParentGuid)
	AND	(EXISTS
