--
-- Remove Schema Binding option from [SSop].[tvf_QuoteSections]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteSections]
	(
		@UserId INT,
		@ParentGuid UNIQUEIDENTIFIER
	)
RETURNS TABLE
AS
RETURN SELECT		qs.ID,
					qs.RowStatus,
					qs.RowVersion,
					qs.Guid,
					qs.SortOrder,
					qs.Name,
					rs.Number AS RibaStage,
					qst.Net,
					qst.Gross
	   FROM			SSop.QuoteSections			  AS qs
	   JOIN			SSop.Quotes					  AS q ON (q.ID = qs.QuoteId)
	   LEFT JOIN	SSop.QuoteSectionTotals		  AS qst ON (qst.ID = qs.ID)
	   JOIN			SJob.RibaStages				  AS rs ON (rs.ID = qs.RibaStageId)
	   WHERE		(qs.RowStatus NOT IN (0, 254))
				AND (qs.ID		> 0)
AND	(EXISTS
			(
					SELECT
							1
					FROM
							SCore.ObjectSecurityForUser_CanRead(qs.Guid, @UserId) oscr
			)
		)
				AND (q.Guid		= @ParentGuid)
	   UNION ALL
	   SELECT		-2,
					1,
					q.RowVersion,
					q.Guid,
					999,
					N'Total',
					0,
					SUM (ISNULL (	qst.Net,
									0
								)
						),
					SUM (ISNULL (	qst.Gross,
									0
								)
						)
	   FROM			SSop.QuoteSections		AS qs
	   JOIN			SSop.Quotes				AS q ON (q.ID	  = qs.QuoteId)
	   LEFT JOIN	SSop.QuoteSectionTotals AS qst ON (qst.ID = qs.ID)
	   WHERE		(qs.RowStatus NOT IN (0, 254))
				AND (qs.ID		> 0)
				AND (q.Guid		= @ParentGuid)
		GROUP BY	q.RowVersion, q.Guid
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[EnquiryService_ExtendedInfo]
--
GO
CREATE OR ALTER VIEW	[SSop].[EnquiryService_ExtendedInfo]
AS
SELECT	es.Id,
		es.RowStatus,
		es.RowVersion,
		es.Guid,
		ISNULL(quote.QuoteID, -1) AS QuoteID,
		quote.DateAccepted,
		quote.DateSent,
		quote.DateRejected,
		quote.QuoteNet,
		ISNULL(quote.Number, 0) AS Number,
		ISNULL(Quote.RevisionNumber, 0) AS RevisionNumber,
		quote.DateDeclinedToQuote AS DeclinedToQuoteDate, --[CBLD-592]
		quote.DeclinedToQuoteReason AS DeclinedToQuoteReason
FROM	SSop.EnquiryServices es
OUTER APPLY 
	(
		SELECT	q.ID AS QuoteID,
				q.DateAccepted,
				q.DateSent, 
				q.DateRejected,
				q.DateDeclinedToQuote, -- [CBLD-592]
				q.DeclinedToQuoteReason,
				q.Number,
				q.RevisionNumber,
				QuoteLines.Net QuoteNet
		FROM	SSop.Quotes AS q
		OUTER APPLY (
			SELECT	SUM(qit.LineNet) AS Net
			FROM	SSop.QuoteItems AS qi 
			JOIN	SSop.QuoteItemTotals AS qit ON (qit.ID = qi.ID)
			WHERE	(qi.QuoteId = q.ID)
				AND	(qi.RowStatus NOT IN (0, 254))
		) QuoteLines
		WHERE	(q.EnquiryServiceID = es.ID)
			AND	(q.EnquiryServiceID > -1)
			AND	(NOT EXISTS
					(
						SELECT	1
						FROM	SSop.Quotes AS q2
						WHERE	(q2.EnquiryServiceID = q.EnquiryServiceID)
							AND	(q2.RevisionNumber > q.RevisionNumber)
							AND	(q2.ID <> q.ID)
							AND	(q2.RowStatus NOT IN (0, 254))
							AND	(q2.DeadDate IS NULL)
					)
				)
	) AS Quote
----[CBLD-592: Getting the declined to quote date]
--OUTER APPLY
--	(
--		SELECT en.DateDeclinedToQuote 
--		FROM SSop.Quotes AS en
--		WHERE es.EnquiryId = en.ID
--	) AS Enquiry

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

