-- Remove Schema Binding option from [SSop].[QuoteSectionTotals]
--
GO
CREATE OR ALTER VIEW [SSop].[QuoteSectionTotals]
AS 
SELECT	qi.QuoteSectionId AS ID,
		CONVERT(DECIMAL(9, 2), ROUND(SUM(qit.LineNet), 2)) AS Net,
		CONVERT(DECIMAL(9, 2), ROUND(SUM(qit.LineVat), 2)) AS Vat,
		CONVERT(DECIMAL(9, 2), ROUND(SUM(qit.LineGross), 2)) AS Gross
FROM	SSop.QuoteItems qi
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
WHERE	(qi.RowStatus NOT IN (0, 254))
GROUP BY qi.QuoteSectionId
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[Quote_JobsSummary]
--
GO
CREATE OR ALTER VIEW [SSop].[Quote_JobsSummary]
AS
SELECT		MIN (qi.ID)							   AS ID,
			q.RowStatus,
			q.Guid								   AS QuoteGuid,
			q.Overview,
			--p.Guid								   AS UprnGuid,
			q.IsSubjectToNDA,
			SUM (qit.LineNet)					   AS Net,
			SUM (	CASE
						WHEN rs.Number = 1 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage1Fee,
			SUM (	CASE
						WHEN rs.Number = 2 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage2Fee,
			SUM (	CASE
						WHEN rs.Number = 3 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage3Fee,
			SUM (	CASE
						WHEN rs.Number = 4 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage4Fee,
			SUM (	CASE
						WHEN rs.Number = 5 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage5Fee,
			SUM (	CASE
						WHEN rs.Number = 6 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage6Fee,
			SUM (	CASE
						WHEN rs.Number = 7 THEN qit.LineNet
						ELSE 0
					END
				)								   AS RibaStage7Fee,
			SUM (	CASE
						WHEN rs.Number = 99 THEN qit.LineNet
						ELSE 0
					END
				)								   AS PreConstructionStageFee,
			SUM (	CASE
						WHEN rs.Number = 999 THEN qit.LineNet
						ELSE 0
					END
				)								   AS ConstructionStageFee,
			ou.Guid								   AS OrganisationalUnitGuid,
			jt.Guid								   AS JobTypeGuid,
			--acc.Guid							   AS ClientAccountGuid,
			--ad.Guid								   AS ClientAddressGuid,
			--c.Guid								   AS ClientContactGuid,
			cr.Guid								   AS ContractGuid,
			--agent_acc.Guid						   AS AgentAccountGuid,
			--agent_ad.Guid						   AS AgentAddressGuid,
			--agent_c.Guid						   AS AgentContactGuid,
			'00000000-0000-0000-0000-000000000000' AS IdentityGuid,
			-1									   AS QuoteItemId,
			q.ExternalReference,
			SUM (qit.LineNet)					   AS AgreedFee,
			jt.Name								   AS JobType,
			q.DateAccepted,
			q.FeeCap,
			--proj.Guid							   AS ProjectGuid,
			ISNULL (   crs.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   )							   AS CurrentRibaStageGuid,
			ISNULL (   ars.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   )							   AS AppointedRibaStageGuid,
			q.ValueOfWork,
			acr.Guid							   AS AgentContractGuid
FROM		SSop.QuoteItems			  AS qi
JOIN		SSop.QuoteItemTotals	  AS qit ON (qit.ID				= qi.ID)
JOIN		SJob.RibaStages			  AS rs ON (rs.ID				= qi.ProvideAtStageID)
JOIN		SProd.Products			  AS p2 ON (p2.ID				= qi.ProductId)
JOIN		SJob.JobTypes			  AS jt ON (p2.CreatedJobType	= jt.ID)
JOIN		SSop.Quotes				  AS q ON (q.ID					= qi.QuoteId)
JOIN		SCore.OrganisationalUnits AS ou ON (ou.ID				= q.OrganisationalUnitID)
JOIN		SSop.Contracts			  AS cr ON (cr.ID				= q.ContractID)
JOIN		SSop.Contracts			  AS acr ON (acr.ID				= q.AgentContractID)
JOIN		SSop.EnquiryServices	  AS es ON (es.ID				= q.EnquiryServiceID)
JOIN		SSop.Enquiries			  AS e ON (e.ID					= es.EnquiryId)
JOIN		SJob.RibaStages			  AS crs ON (crs.ID				= e.CurrentProjectRibaStageID)
JOIN		SJob.RibaStages			  AS ars ON (ars.ID				= q.AppointmentFromRibaStageId)
--JOIN		SCrm.Accounts			  AS acc ON (acc.ID				= e.ClientAccountId)
--JOIN		SCrm.AccountAddresses	  AS ad ON (ad.ID				= e.ClientAddressId)
--JOIN		SCrm.AccountContacts	  AS c ON (c.ID					= e.ClientAccountContactId)
--JOIN		SCrm.Accounts			  AS agent_acc ON (agent_acc.ID = e.AgentAccountId)
--JOIN		SCrm.AccountAddresses	  AS agent_ad ON (agent_ad.ID	= e.AgentAddressId)
--JOIN		SCrm.AccountContacts	  AS agent_c ON (agent_c.ID		= e.AgentAccountContactId)
--JOIN		SJob.Properties			  AS p ON (p.ID					= e.PropertyId)
--JOIN		SSop.Projects			  AS proj ON (proj.ID			= e.ProjectId)
WHERE		(qi.RowStatus NOT IN (0, 254))
		AND (qi.Quantity			> 0)
		AND (qi.CreatedJobId		< 0)
		AND (qi.DoNotConsolidateJob = 0)
		AND (NOT EXISTS
	(
		SELECT	1
		FROM	SProd.Products AS prod2
		WHERE	(prod2.NeverConsolidate = 1)
			AND (qi.ProductId			= prod2.ID)
	)
			)
GROUP BY	q.RowStatus,
			q.Guid,
			q.Overview,
			--p.Guid,
			q.IsSubjectToNDA,
			jt.Guid,
			jt.Name,
			ou.Guid,
			--acc.Guid,
			--ad.Guid,
			--c.Guid,
			cr.Guid,
			--agent_acc.Guid,
			--agent_ad.Guid,
			--agent_c.Guid,
			q.ExternalReference,
			q.DateAccepted,
			q.FeeCap,
			--proj.Guid,
			crs.Guid,
			ars.Guid,
			q.ValueOfWork,
			q.AgentContractID,
			acr.Guid
UNION ALL
SELECT		qi.ID								  AS ID,
			q.RowStatus,
			q.Guid,
			q.Overview,
			--p.Guid,
			q.IsSubjectToNDA,
			qit.LineNet,
			CASE
				WHEN rs.Number = 1 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 2 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 3 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 4 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 5 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 6 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 7 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 99 THEN qit.LineNet
				ELSE 0
			END,
			CASE
				WHEN rs.Number = 999 THEN qit.LineNet
				ELSE 0
			END,
			ou.Guid,
			jt.Guid,
			--acc.Guid,
			--ad.Guid,
			--c.Guid,
			cr.Guid,
			--agent_acc.Guid,
			--agent_ad.Guid,
			--agent_c.Guid,
			'00000000-0000-0000-0000-000000000000',
			qi.ID,
			q.ExternalReference,
			--vow.Guid,
			qi.Net,
			jt.Name,
			q.DateAccepted,
			q.FeeCap,
			--proj.Guid							  AS ProjectGuid,
			ISNULL (   crs.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   ),
			ISNULL (   ars.Guid,
					   '00000000-0000-0000-0000-000000000000'
				   ),
			q.ValueOfWork,
			acr.Guid
FROM		SSop.QuoteItems			  AS qi
JOIN		SSop.QuoteItemTotals	  AS qit ON (qit.ID				= qi.ID)
JOIN		SJob.RibaStages			  AS rs ON (rs.ID				= qi.ProvideAtStageID)
JOIN		SSop.Quotes				  AS q ON (q.ID					= qi.QuoteId)
JOIN		SProd.Products			  AS prod ON (prod.ID			= qi.ProductId)
JOIN		SJob.JobTypes			  AS jt ON (jt.ID				= prod.CreatedJobType)
JOIN		SCore.OrganisationalUnits AS ou ON (ou.ID				= q.OrganisationalUnitID)
JOIN		SSop.Contracts			  AS cr ON (cr.ID				= q.ContractID)
JOIN		SSop.Contracts			  AS acr ON (acr.ID				= q.AgentContractID)
JOIN		SSop.EnquiryServices	  AS es ON (es.ID				= q.EnquiryServiceID)
JOIN		SSop.Enquiries			  AS e ON (e.ID					= es.EnquiryId)
JOIN		SJob.RibaStages			  AS crs ON (crs.ID				= e.CurrentProjectRibaStageID)
JOIN		SJob.RibaStages			  AS ars ON (ars.ID				= q.AppointmentFromRibaStageId)
--JOIN		SCrm.Accounts			  AS acc ON (acc.ID				= e.ClientAccountId)
--JOIN		SCrm.AccountAddresses	  AS ad ON (ad.ID				= e.ClientAddressId)
--JOIN		SCrm.AccountContacts	  AS c ON (c.ID					= e.ClientAccountContactId)
--JOIN		SCrm.Accounts			  AS agent_acc ON (agent_acc.ID = e.AgentAccountId)
--JOIN		SCrm.AccountAddresses	  AS agent_ad ON (agent_ad.ID	= e.AgentAddressId)
--JOIN		SCrm.AccountContacts	  AS agent_c ON (agent_c.ID		= e.AgentAccountContactId)
--JOIN		SJob.Properties			  AS p ON (p.ID					= e.PropertyId)
--JOIN		SSop.Projects			  AS proj ON (proj.ID			= e.ProjectId)
WHERE		(qi.RowStatus NOT IN (0, 254))
		AND (qi.Quantity			  > 0)
		AND (qi.CreatedJobId		  < 0)
		AND
		  (
			  (prod.NeverConsolidate  = 1)
		   OR (qi.DoNotConsolidateJob = 1)
		  );
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[tvf_QuoteItems]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteItems]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
AS RETURN	
SELECT  qi.ID,
        qi.RowStatus,
        qi.Guid,
		qi.SortOrder,
		qi.Details,
		p.Code,
		qi.Quantity,
		qi.Net,
		qit.Vat,
		qit.Gross,
		qit.LineNet,
		qit.LineVat,
		qit.LineGross
FROM    SSop.QuoteItems qi
JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
JOIN	SProd.Products p ON (p.ID = qi.ProductId)	
WHERE   (qi.RowStatus NOT IN (0, 254))
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(qi.Guid, @UserId) oscr
			)
		)
	AND	(q.Guid = @ParentGuid)
UNION ALL 
SELECT	-2,
		1,
		'00000000-0000-0000-0000-000000000000',
		999,
		N'Total',
		N'',
		SUM(qi.Quantity),
		SUM(qi.Net),
		SUM(qit.Vat),
		SUM(qit.Gross),
		SUM(qit.LineNet),
		SUM(qit.LineVat),
		SUM(qit.LineGross)
FROM    SSop.QuoteItems qi
JOIN	SSop.Quotes q ON (q.ID = qi.QuoteId)
JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
WHERE   (qi.RowStatus NOT IN (0, 254))
	AND	(q.Guid = @ParentGuid)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[tvf_QuoteFeeDrawdown]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_QuoteFeeDrawdown] 
(
    @UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
AS
RETURN 
SELECT		q.ID,
			q.RowStatus,
			q.Guid,
			CASE
				WHEN rs.Number = 0 THEN N'Fee Cap'
				WHEN rs.Number = 99 THEN N'Pre-Construction'
				WHEN rs.Number = 999 THEN N'Construction'
				ELSE CONVERT (	 NVARCHAR(10),
								 rs.Number
							 )
			END AS Stage,
			ISNULL(CASE rs.Number
				WHEN 0 THEN q.FeeCap
				ELSE stages.Net
			END, 0) AS Quoted
FROM		SSop.Quotes		AS q
CROSS JOIN	SJob.RibaStages AS rs
OUTER APPLY
			(
				SELECT		CASE WHEN qi.ProvideAtStageID = -1 THEN 2 ELSE qi.ProvideAtStageID END  AS RibaStage,
							SUM(qit.LineNet) AS Net
				FROM		SSop.QuoteItems		AS qi
				JOIN		SSop.QuoteItemTotals AS qit ON (qi.ID = qit.ID)
				WHERE		(qi.QuoteId = q.ID)
						AND (qi.RowStatus NOT IN (0, 254))
						AND	(CASE WHEN qi.ProvideAtStageID = -1 THEN 2 ELSE qi.ProvideAtStageID END = rs.ID)
				GROUP BY	CASE WHEN qi.ProvideAtStageID = -1 THEN 2 ELSE qi.ProvideAtStageID END
			)				AS stages
WHERE		(rs.ID	> 0)
		AND (q.Guid = @ParentGuid)
		AND	(
				(
						(rs.IsRealStage = 1)
						AND	(NOT EXISTS
								(
									SELECT	1
									FROM	SSop.QuoteSections eqs
									JOIN	SJob.RibaStages ers ON (ers.ID = eqs.RibaStageId)
									WHERE	(eqs.QuoteId = q.ID)
										AND	(eqs.RowStatus NOT IN (0, 254))
										AND	(ers.Number IN (99, 999))
								)
							)
					)
				OR	(
						(rs.IsRealStage = 0)
						AND	(EXISTS
								(
									SELECT	1
									FROM	SSop.QuoteSections eqs
									JOIN	SJob.RibaStages ers ON (ers.ID = eqs.RibaStageId)
									WHERE	(eqs.QuoteId = q.ID)
										AND	(eqs.RowStatus NOT IN (0, 254))
										AND	(ers.Number IN (99, 999))
								)
							)
					)
			)
UNION ALL
SELECT	q.Id,
		q.RowStatus,
		q.Guid,
		N'Total (ex. Fee Cap.)',
		sections.Total AS Quoted
FROM	SSop.Quotes q
OUTER APPLY (
	SELECT SUM(qit.LineNet) AS Total
	FROM	SSop.QuoteItems  qi
	JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
	WHERE	(qi.QuoteId = q.ID)
) AS sections
WHERE	(q.Guid = @ParentGuid)
UNION ALL
SELECT	q.Id,
		q.RowStatus,
		q.Guid,
		N'Total (inc. Fee Cap.)',
		sections.Total + q.FeeCap AS Quoted
FROM	SSop.Quotes q
OUTER APPLY (
	SELECT SUM(qit.LineNet) AS Total
	FROM	SSop.QuoteItems  qi
	JOIN	SSop.QuoteItemTotals qit ON (qit.ID = qi.ID)
	WHERE	(qi.QuoteId = q.ID)
) AS sections
WHERE	(q.Guid = @ParentGuid)

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[tvf_Enquiries]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_Enquiries]
(
	@UserId INT
)
RETURNS TABLE
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		CASE WHEN e.Revision = 0 THEN e.Number ELSE (e.Number + N' (' + CONVERT(NVARCHAR(2), e.Revision) + N') ') END AS Number,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		uprn.AssetNumber AS UPRN,
		ecf.EnquiryStatus,
		ISNULL(p.IsSubjectToNDA, e.IsSubjectToNDA) AS IsSubjectToNDA,
		CASE WHEN ServiceTypes.Name IS NULL THEN N'Multi Discipline' ELSE ServiceTypes.Name END AS Disciplines,
		org.Name AS OrgUnit,
		e.Date 
FROM    SSop.Enquiries e
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
JOIN	SSop.Projects AS p ON (p.ID = e.ProjectId)
JOIN	SCore.OrganisationalUnits AS org ON (org.ID = e.OrganisationalUnitID)
OUTER APPLY (
	SELECT	jt.Name
	FROM	SJob.JobTypes AS jt
	WHERE	(EXISTS
				(
					SELECT	1
					FROM 	SSop.EnquiryServices AS es 
					WHERE	(es.JobTypeId = jt.ID)
						AND	(es.EnquiryId = e.ID)
						AND	(es.RowStatus NOT IN (0, 254))
						AND	(NOT EXISTS
								(
									SELECT	1
									FROM	SSop.EnquiryServices es2 
									WHERE	(es2.ID <> es.ID)
										AND	(es2.EnquiryId = es.EnquiryId)
										AND	(es2.RowStatus NOT IN (0, 254))
								)
							)
				)
			)
) AS ServiceTypes
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[tvf_OpenEnquiries]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_OpenEnquiries]
(
	@UserId INT
)
RETURNS TABLE
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		CASE WHEN e.Revision = 0 THEN e.Number ELSE (e.Number + N' (' + CONVERT(NVARCHAR(2), e.Revision) + N') ') END AS Number,
		e.QuotingDeadlineDate,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		ecf.EnquiryStatus
FROM    SSop.Enquiries e
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)
	AND	(e.DeclinedToQuoteDate IS NULL)
	AND	(EXISTS
			(
				SELECT	1
				FROM	SSop.EnquiryServices es 
				WHERE	(es.EnquiryId = e.ID)
					AND	(es.RowStatus NOT IN (0, 254))
					AND	(es.QuoteId < 0)
			)
		)
	AND	(e.Date > DATEADD(MONTH, -6, GETDATE()))
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[tvf_EnquiriesForQuoteReview]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiriesForQuoteReview]
(
	@UserId INT
)
RETURNS TABLE
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		e.Number,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN acc.Name <> N'' THEN acc.Name ELSE e.ClientName END AS Account,
		-- New fields
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		ecf.EnquiryStatus
FROM    SSop.Enquiries e
JOIN	SCrm.Accounts acc ON (acc.ID = e.ClientAccountID)
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)
	AND	(e.IsReadyForQuoteReview = 1)
	AND	(EXISTS
			(
				SELECT	1
				FROM	SSop.EnquiryServices es
				WHERE	(es.EnquiryId = e.ID)
					AND	(es.RowStatus NOT IN (0, 254))
					AND	(NOT EXISTS
							(
								SELECT	1
								FROM	SSop.Quotes AS q
								WHERE	(q.EnquiryServiceID = es.ID)
									AND	(q.RowStatus NOT IN (0, 254))
							)
						)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SSop].[Enquiry_CalculatedFields]
--
GO
CREATE OR ALTER VIEW [SSop].[Enquiry_CalculatedFields]
AS
SELECT	
	e.ID,
	EnquiryStatus =
		CASE
			-- 1. TVF status is a final status: use it
			WHEN s.QuotingStatus IS NOT NULL 
			     AND s.QuotingStatus NOT IN (N'Sent', N'Part Sent', N'Quoting')
			     THEN s.QuotingStatus

			-- 2. TVF status is transitional AND we have fallback data
			WHEN s.QuotingStatus IN (N'Sent', N'Part Sent', N'Quoting')
				 AND (
					  e.DeadDate IS NOT NULL
				   OR e.DeclinedToQuoteDate IS NOT NULL
				   OR e.QuotingDeadlineDate < GETDATE()
				   OR e.QuotingDeadlineDate < DATEADD(DAY, 2, GETDATE())
				   OR e.ChaseDate2 IS NOT NULL
				   OR e.ChaseDate1 IS NOT NULL
				   OR (
					   e.IsReadyForQuoteReview = 1
					   AND NOT EXISTS (
						  SELECT 1 FROM SSop.EnquiryServices es 
						  JOIN SSop.Quotes q ON es.ID = q.EnquiryServiceID 
						  WHERE es.EnquiryId = e.ID AND q.DateSent IS NOT NULL
					   )
				   )
				 )
			THEN 
			   CASE
				   WHEN e.DeadDate IS NOT NULL THEN N'Dead'
				   WHEN e.DeclinedToQuoteDate IS NOT NULL THEN N'Declined'
				   WHEN e.QuotingDeadlineDate < GETDATE() THEN N'Deadline Missed'
				   WHEN e.QuotingDeadlineDate < DATEADD(DAY, 2, GETDATE()) THEN N'Deadline Approaching'
				   WHEN e.ChaseDate2 IS NOT NULL THEN N'2nd Chase'
				   WHEN e.ChaseDate1 IS NOT NULL THEN N'1st Chase'
				   WHEN e.IsReadyForQuoteReview = 1 
					 AND NOT EXISTS (
						  SELECT 1 FROM SSop.EnquiryServices es 
						  JOIN SSop.Quotes q ON es.ID = q.EnquiryServiceID 
						  WHERE es.EnquiryId = e.ID AND q.DateSent IS NOT NULL
					 ) THEN N'Ready for Quote'
				   ELSE s.QuotingStatus
			   END

			-- 3. No fallback data – return whatever TVF gave us
			WHEN s.QuotingStatus IS NOT NULL THEN s.QuotingStatus

			-- 4. Only if no TVF and no fallback
			ELSE N'New'
		END
FROM	SSop.Enquiries e
OUTER APPLY SSop.tvf_GetEnquiryStatuses(e.Id) as s;

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

