--
-- Remove Schema Binding option from [SJob].[tvf_Jobs_DRRNeedsReview]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_DRRNeedsReview]
	(
		@UserId INT
	)
RETURNS TABLE
AS
RETURN SELECT	j.ID,
				j.RowStatus,
				j.RowVersion,
				j.Guid,
				j.Number,
				j.JobDescription,
				j.JobTypeID,
				client.Name AS Client,
				jt.Name		AS JobTypeName,
				i.Guid		AS SurveyorGuid,
				i.FullName	AS SurveyorName,
				DRR.ReviewedDateTimeUTC,
				js.IsSubjectToNDA
	   FROM		SJob.Jobs		 AS j
	   JOIN		SJob.JobStatus AS js ON (js.ID = j.ID)
	   JOIN		SJob.JobTypes	 AS jt ON (j.JobTypeID = jt.ID)
	   JOIN		SCore.Identities AS i ON (j.SurveyorID = i.ID)
	   JOIN		SCrm.Accounts	 AS client ON (client.ID = j.ClientAccountID)
	   CROSS APPLY
				(
					SELECT	m.ReviewedDateTimeUTC
					FROM	SJob.Milestones		AS m
					JOIN	SJob.MilestoneTypes AS mt ON (mt.ID = m.MilestoneTypeID)
					WHERE	(m.JobID				 = j.ID)
						AND (m.RowStatus NOT IN (0, 254))
						AND (m.IsComplete			 = 0)
						AND (mt.Code				 = N'DESIGNHAZ')
						AND (m.CompletedDateTimeUTC IS NULL)
						AND
						  (
							  (m.ReviewedDateTimeUTC IS NULL)
						   OR (m.ReviewedDateTimeUTC < DATEADD (   WEEK,
																   -8,
																   GETDATE ()
															   )
							  )
						  )
						AND (NOT EXISTS
						(
							SELECT	1
							FROM	SJob.Milestones AS m1
							WHERE	(m1.JobID				= j.ID)
								AND (m1.MilestoneTypeID		= m.MilestoneTypeID)
								AND (m1.RowStatus NOT IN (0, 254))
								AND (m1.ReviewedDateTimeUTC < m.ReviewedDateTimeUTC)
						)
							)
				)				 AS DRR
	   WHERE	(j.RowStatus NOT IN (0, 254))
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
				)
			AND (j.IsActive			= 1)
			AND (j.IsPendingCompletion = 0)
			AND (j.SurveyorID			= @UserId);

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

