--
-- Remove Schema Binding option from [SCore].[tvf_PropertyGroupsForEntityType]
--
GO
CREATE OR ALTER FUNCTION [SCore].[tvf_PropertyGroupsForEntityType]
	(
		@Guid UNIQUEIDENTIFIER,
		@UserId INT
	)
RETURNS TABLE
AS
RETURN SELECT		pg.RowStatus,
					pg.RowVersion,
					pg.Guid,
					pg.Name,
					e.Guid	 AS EntityTypeGuid,
					ll.Guid	 AS LanguageLabelGuid,
					pgl.Guid AS PropertyGroupLayoutGuid,
					pgl.Name AS PropertyGroupLayout,
					pg.IsHidden,
					pg.SortOrder,
					pg.IsCollapsable,
					pg.IsDefaultCollapsed,
					pg.IsDefaultCollapsed_Mobile,
					pg.ShowOnMobile,
					os.CanRead,
					os.CanWrite,
					ISNULL (   lt.Label,
							   N''
						   ) AS Label
	   FROM			SCore.EntityPropertyGroupsV	  AS pg
	   JOIN			SCore.LanguageLabelsV		  AS ll ON (ll.ID = pg.LanguageLabelID)
	   JOIN			SUserInterface.PropertyGroupLayouts pgl ON (pgl.ID = pg.PropertyGroupLayoutID)
	   LEFT JOIN	SCore.EntityTypesV			  AS e ON (pg.EntityTypeID = e.ID)
	   OUTER APPLY	SCore.ObjectSecurityForUser (	pg.Guid,
													@UserId
												) AS os
	   OUTER APPLY	SCore.ObjectLabelForUser (	 pg.LanguageLabelID,
												 @UserId
											 ) AS lt
	   WHERE		(ISNULL(e.Guid, '00000000-0000-0000-0000-000000000000') = @Guid)
				 OR (pg.ID	= -1);
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Remove Schema Binding option from [SCore].[tvf_PropertiesForEntityType]
--
GO
CREATE OR ALTER FUNCTION [SCore].[tvf_PropertiesForEntityType]
	(
		@Guid UNIQUEIDENTIFIER,
		@UserId INT
	)
RETURNS TABLE 
AS
RETURN SELECT		p.RowStatus,
					p.RowVersion,
					p.Guid,
					p.Name,
					e.Guid	  AS EntityTypeGuid,
					ll.Guid	  AS LanguageLabelGuid,
					edt.Guid  AS EntityDataTypeGuid,
					p.IsReadOnly,
					p.IsImmutable,
					p.IsHidden,
					p.IsCompulsory,
					p.MaxLength,
					p.Precision,
					p.Scale,
					p.DoNotTrackChanges,
					epg.Guid  AS EntityPropertyGroupGuid,
					p.SortOrder,
					p.GroupSortOrder,
					ISNULL (   os.CanRead,
							   0
						   )  AS CanRead,
					ISNULL (   os.CanWrite,
							   0
						   )  AS CanWrite,
					edt.Name  AS EntityDataTypeName,
					ISNULL (   lt.Label,
							   p.Name
						   )  AS Label,
					ddld.Guid AS DropDownListDefinitionGuid,
					ddld.DetailPageUrl,
					ddld.InformationPageUrl,
					ddld.IsDetailWindowed,
					ddlde.Guid AS ForeignEntityTypeGuid,
					p.IsObjectLabel,
					p.IsParentRelationship,
					hobt.Guid AS EntityHoBTGuid,
					p.IsLongitude,
					p.IsLatitude,
					p.IsUppercase,
					p.IsIncludedInformation,
					p.FixedDefaultValue,
					p.SqlDefaultValueStatement,
					p.AllowBulkChange,
					p.IsVirtual,
					p.ShowOnMobile,
					p.IsAlwaysVisibleInGroup,
					p.IsAlwaysVisibleInGroup_Mobile
	   FROM			SCore.EntityProperties					AS p
	   JOIN			SCore.EntityDataTypes					AS edt ON (p.EntityDataTypeID = edt.ID)
	   JOIN			SCore.EntityHobts						AS hobt ON (p.EntityHoBTID = hobt.ID)
	   JOIN			SCore.EntityTypes						AS e ON (hobt.EntityTypeID = e.ID)
	   JOIN			SCore.EntityPropertyGroups				AS epg ON (p.EntityPropertyGroupID = epg.ID)
	   JOIN			SUserInterface.DropDownListDefinitions AS ddld ON (ddld.ID = p.DropDownListDefinitionID)
	   JOIN			SCore.EntityTypes						AS ddlde ON (ddlde.ID = ddld.EntityTypeId)
	   JOIN			SCore.LanguageLabels					AS ll ON (ll.ID = p.LanguageLabelID)
	   OUTER APPLY	SCore.ObjectSecurityForUser (	p.Guid,
													@UserId
												)			AS os
	   OUTER APPLY	SCore.ObjectLabelForUser (	 p.LanguageLabelID,
												 @UserId
											 ) AS lt
	   WHERE		(e.Guid = @Guid)
				AND	(p.RowStatus NOT IN (0, 254))

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

