CREATE OR ALTER FUNCTION [SCore].[tvf_Identities]
	(
		@UserId INT
	)
RETURNS TABLE
            --WITH SCHEMABINDING
AS
RETURN SELECT		i.ID,
				i.RowStatus,
				i.RowVersion,
				i.Guid,
				i.FullName,
				i.EmailAddress,
				ou.Name AS OrganisationalUnit,
				os.CanWrite
	   FROM			SCore.Identities			  AS i
	   JOIN		Score.OrganisationalUnits ou ON (ou.ID = i.OriganisationalUnitId)
