--
-- Create or alter view [SCore].[ObjectSecurityForUser_CanWritev]
--
GO
CREATE OR ALTER VIEW [SCore].[ObjectSecurityForUser_CanWritev]
        --WITH SCHEMABINDING
AS
	SELECT	do.Guid,
			i.ID
	FROM	SCore.DataObjects do
	CROSS JOIN	SCore.Identities i
	WHERE	(NOT EXISTS
				(
					SELECT	1
					FROM	SCore.ObjectSecurity os1
					WHERE	(os1.UserId = i.ID)
						AND	(os1.ObjectGuid = do.Guid)
						AND	(os1.DenyWrite > 0)
						AND	(os1.RowStatus NOT IN (0, 254))
				)
			)
		AND	(NOT EXISTS
				(
					SELECT	1
					FROM	SCore.ObjectSecurity os1
					JOIN	SCore.UserGroups ug ON (os1.GroupId = ug.GroupID)
					WHERE	(ug.IdentityID = i.ID)
						AND	(os1.ObjectGuid = do.Guid)
						AND	(os1.DenyWrite > 0)
						AND	(os1.RowStatus NOT IN (0, 254))
				)
			)
		AND	(
				( EXISTS
					(
						SELECT	1
						FROM	SCore.ObjectSecurity os1
						WHERE	(os1.UserId = i.ID)
							AND	(os1.ObjectGuid = do.Guid)
							AND	(os1.CanWrite > 0)
							AND	(os1.RowStatus NOT IN (0, 254))
					)
				)
			OR	( EXISTS
					(
						SELECT	1
						FROM	SCore.ObjectSecurity os1
						JOIN	SCore.UserGroups ug ON (os1.GroupId = ug.GroupID)
						WHERE	(ug.IdentityID = i.ID)
							AND	(os1.ObjectGuid = do.Guid)
							AND	(os1.CanWrite > 0)
							AND	(os1.RowStatus NOT IN (0, 254))
					)
				)
			OR	(NOT EXISTS
					(
						SELECT	1
						FROM	SCore.ObjectSecurity hos3
						WHERE	(hos3.ObjectGuid = do.Guid)
							AND (hos3.RowStatus NOT IN (0, 254))
					)
				)
			)
	 
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SCore].[DirectoryObjectSecurity]
--
GO
CREATE OR ALTER VIEW [SCore].[DirectoryObjectSecurity]
               --WITH SCHEMABINDING
AS
SELECT	os.ObjectGuid, 
		COALESCE(i.EmailAddress, g.DirectoryId, N'') AS DirectoryId,
		CASE	WHEN os.CanWrite = 1 THEN N'write'
				WHEN os.CanWrite = 0 AND os.CanRead = 1 THEN N'read'
				ELSE N''
		END AS [role]
FROM	SCore.ObjectSecurity os 
LEFT JOIN	SCore.Identities i ON (i.ID = os.UserId)
LEFT JOIN	SCore.Groups g ON (g.ID = os.GroupId)
WHERE	(os.RowStatus = 1)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

