(
    @UserId INT,
    @ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
               --WITH SCHEMABINDING
AS
RETURN 
SELECT  llt.ID,
        llt.RowStatus, 
        llt.RowVersion,
        llt.Guid,
		llt.Text,
