--
-- Create or alter view [SCrm].[Accounts_CalculatedFields]
--
GO
CREATE OR ALTER VIEW [SCrm].[Accounts_CalculatedFields]
	    --WITH SCHEMABINDING
AS
SELECT	a.ID,
		a.Guid,
		a.RowStatus,
		a.RowVersion,
		ad.FormattedAddressCR MainAddress,
		phone.Value AS MainPhone,
		email.Value AS MainEmail
FROM	SCrm.Accounts a
JOIN	SCrm.AccountAddresses aa ON (aa.ID = a.MainAccountAddressId)
JOIN	SCrm.Addresses ad ON (ad.ID = aa.AddressID)
JOIN	SCrm.AccountContacts ac ON (ac.Id = a.MainAccountContactId)
JOIN	SCrm.Contacts c ON (c.ID = ac.ContactID)
OUTER APPLY 
(
	SELECT	cd.Value 
	FROM	SCrm.ContactDetails cd 
	JOIN	SCrm.ContactDetailTypes cdt ON (cdt.ID = cd.ContactDetailTypeID)
	WHERE	(cd.ContactID = c.ID)
		AND	(cdt.Name = N'Office')
		AND	(
				(cd.IsDefault = 1)
			OR	(NOT EXISTS
					(
						SELECT	1
						FROM	SCrm.ContactDetails cd2
						WHERE	(cd2.ContactDetailTypeID = cdt.ID)
							AND	(cd2.ContactID = c.ID)
							AND	(cd2.ID <> cd.ID)
							AND	(cd2.RowStatus NOT IN (0, 254))
					)
				)
			)
) AS Phone
OUTER APPLY 
(
	SELECT	cd.Value 
	FROM	SCrm.ContactDetails cd 
	JOIN	SCrm.ContactDetailTypes cdt ON (cdt.ID = cd.ContactDetailTypeID)
	WHERE	(cd.ContactID = c.ID)
		AND	(cdt.Name = N'E-Mail')
		AND	(
				(cd.IsDefault = 1)
			OR	(NOT EXISTS
					(
						SELECT	1
						FROM	SCrm.ContactDetails cd2
						WHERE	(cd2.ContactDetailTypeID = cdt.ID)
							AND	(cd2.ContactID = c.ID)
							AND	(cd2.ID <> cd.ID)
							AND	(cd2.RowStatus NOT IN (0, 254))
					)
				)
			)
) AS Email

	
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SCrm].[LiveSageColourAccounts]
--
GO
CREATE OR ALTER VIEW [SCrm].[LiveSageColourAccounts]
--WITH SCHEMABINDING
AS 
SELECT
    root_hobt.Guid,
    root_hobt.RowStatus,
    root_hobt.Name,
    root_hobt.ConcatenatedNameCode,
    -- New computed column for colour logic
    CASE 
        WHEN root_hobt.Name = root_hobt.ConcatenatedNameCode 
            THEN '#000000' -- Black
            ELSE '#FF0000' -- Red
    END AS ColourHex
FROM
    SCrm.Accounts root_hobt
JOIN
