--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_Dormant] 
(
    @UserId INT
)
RETURNS TABLE
    --WITH SCHEMABINDING
AS
RETURN 
SELECT  j.ID,
        j.RowStatus,
        j.RowVersion,
        j.Guid,
        j.Number,
        j.JobDescription,
        j.JobTypeID,
        jt.Name AS JobTypeName,
		i.Guid SurveyorGuid,
		client.Name + N' / ' + agent.Name AS  ClientAgent,
		i.FullName AS SurveyorName, 
		prop.FormattedAddressComma,
		js.IsSubjectToNDA,
		j.IsComplete,
		js.JobStatus,
		j.JobDormant,
		org.Name AS OrgUnit
FROM    SJob.Jobs j
JOIN	SJob.JobStatus js ON (js.ID = j.ID)
JOIN    SJob.JobTypes jt ON (j.JobTypeID = jt.ID)
