WHERE   (j.RowStatus  NOT IN (0, 254))
	AND	(j.Id > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(j.Guid, @UserId) oscr
			)
		)
	AND	(j.IsComplete = 0)
	AND	(j.JobDormant IS NOT NULL)
	AND	(j.SurveyorID = @UserId)
