--
-- Create or alter function [SJob].[MyWork_Activities]
--
GO
CREATE OR ALTER FUNCTION [SJob].[MyWork_Activities]
(
	@UserId INT
)
RETURNS TABLE
	   --WITH SCHEMABINDING
AS RETURN
SELECT	a.ID,
		a.Guid,
		a.RowVersion,
		a.RowStatus,
		a.Date,
		a.EndDate,
		a.Title,
		aty.Name   AS ActivityType,
		ast.Name   AS ActivityStatus,
		i.FullName AS SurveyorName,
		j.Number   AS JobNumber,
		CONVERT(NVARCHAR(20), CASE WHEN (EXISTS (SELECT 1 FROM SFin.InvoiceRequestItems iri WHERE (iri.ActivityId = a.ID) AND (iri.RowStatus NOT IN (0, 254)))) THEN 1 ELSE 0 END) + N' / '
		+ CONVERT(NVARCHAR(20), CASE WHEN (EXISTS (SELECT 1 FROM SFin.TransactionDetails td WHERE (td.ActivityId = a.ID) AND (td.RowStatus NOT IN (0, 254)))) THEN 1 ELSE 0 END) AS RequestedInvoiced
FROM	SJob.Activities		AS a
JOIN	SJob.ActivityStatus AS ast ON (ast.ID = a.ActivityStatusID)
JOIN	SJob.ActivityTypes	AS aty ON (aty.ID = a.ActivityTypeID)
JOIN	SJob.Jobs			AS j ON (j.ID	  = a.JobID)
JOIN	SCore.Identities	AS i ON (i.ID	  = a.SurveyorID)
WHERE	(a.SurveyorID = @UserId)
	AND	(a.Date BETWEEN DATEADD (	WEEK,
									-1,
									DATEADD (	WEEK,
												DATEDIFF (	 WEEK,
															 0,
															 GETDATE ()
														 ),
												0
											)
								) AND DATEADD (	  WEEK,
												  1,
												  DATEADD (	  WEEK,
															  DATEDIFF (   WEEK,
																		   0,
																		   GETDATE ()
																	   ),
															  0
														  )
											  )
		)
	AND (a.RowStatus NOT IN (0, 254));


GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SFin].[tvf_InvoiceRequests]
--
GO
CREATE OR ALTER FUNCTION [SFin].[tvf_InvoiceRequests]
	(
		@UserId INT
	)
RETURNS TABLE
--WITH SCHEMABINDING
AS
RETURN SELECT		ir.ID,
					ir.RowStatus,
					ir.RowVersion,
					ir.Guid,
					ir.Notes,
					ir.CreatedDateTimeUTC,
					i.Guid					  AS RequesterUserId,
					i.FullName				  AS SurveyorName,
					j.Guid					  AS JobId,
					j.Number,
					j.FinanceAccountID,
																		-- [CBLD-522]
					STRING_AGG (   ActT.Name,
								   ', '
							   )			  AS ActivityID,			-- Activity name
																		-- [CBLD-525]
					Acc.Name				  AS ClientName,			-- Client the request is associated with
					SUM (IRI.Net)			  AS Net,					-- Invoice Request Amount
					MAX (Act.EndDate)		  AS EndDate,				-- On or prior to today's date
					j.BillingInstruction	  AS JobBillingInstruction, -- Job billing instruction
					FinAcc.BillingInstruction AS CRMBillingInstruction, -- CRM billing instruction
					CASE
						WHEN MAX (	 CASE
										 WHEN ActT.IsBillable = 0 THEN 'No'
										 ELSE 'Yes'
									 END
								 ) = 'Yes' THEN 'Yes'
						ELSE 'No'
					END						  AS IsBillable
	   FROM			SFin.InvoiceRequests	 AS ir
	   JOIN			SJob.Jobs				 AS j ON (j.ID					 = ir.JobId)
	   JOIN			SCore.Identities		 AS i ON (i.ID					 = ir.RequesterUserId)
	   INNER JOIN	SFin.InvoiceRequestItems AS IRI ON (IRI.InvoiceRequestId = ir.ID) -- NEW => [CBLD-522]
	   INNER JOIN	SJob.Activities			 AS Act ON (IRI.ActivityId		 = Act.ID) -- NEW => [CBLD-522]
	   INNER JOIN	SJob.ActivityTypes		 AS ActT ON (Act.ActivityTypeID	 = ActT.ID) -- NEW => [CBLD-522]
	   INNER JOIN	SCrm.Accounts			 AS Acc ON (Acc.ID				 = j.ClientAccountID) -- NEW => [CBLD-525]
	   LEFT JOIN	SCrm.Accounts			 AS FinAcc ON (FinAcc.ID		 = j.FinanceAccountID)
	   WHERE		(ir.RowStatus NOT IN (0, 254))
				AND (ir.ID			  > 0)
				AND (j.CannotBeInvoiced <> 1)
				AND (EXISTS
		   (
			   SELECT	1
			   FROM		SFin.InvoiceRequestItems AS iri
			   WHERE	(iri.RowStatus NOT IN (0, 254))
					AND (iri.InvoiceRequestId = ir.ID)
		   )
					)
				-- [CBLD-524] Completed Activity
				AND
				  (
					  (EXISTS
		   (
			   SELECT		1
			   FROM			SFin.InvoiceRequestItems AS iri
			   INNER JOIN	SJob.Activities			 AS act ON (iri.ActivityId = act.ID)
			   WHERE		(
								act.ActivityStatusID = 3
							 OR act.ID				 < 0
							)
						AND (iri.InvoiceRequestId	 = ir.ID)  -- Always connect back to main query
		   )
					  )
				   OR (IRI.ActivityId < 0)
				  )
				-- [CBLD-524] Activity must have an associated value
				AND (EXISTS
		   (
			   SELECT	1
			   FROM		SFin.InvoiceRequestItems AS iri
			   WHERE	(iri.RowStatus NOT IN (0, 254))
					AND (iri.Net			  > 0.00)
					AND (iri.InvoiceRequestId = ir.ID)	-- Always connect back to main query
		   )
					)
				-- [CBLD-524] Activity is on or prior to today's date 
				AND
				  (
					  (EXISTS
		   (
			   SELECT		1
			   FROM			SFin.InvoiceRequestItems AS iri
			   INNER JOIN	SJob.Activities			 AS Act ON (iri.ActivityId = Act.ID)
			   WHERE		(iri.RowStatus NOT IN (0, 254))
						AND (CAST (Act.EndDate AS DATE) <= CAST (GETDATE () AS DATE))
						AND (iri.InvoiceRequestId		= ir.ID)  -- Always connect back to main query
		   )
					  )
				   OR (IRI.ActivityId < 0)
				  )
				AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
					)
				AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	ir.Guid,
																@UserId
															) AS oscr
		   )
					)
				AND (NOT EXISTS
		   (
			   SELECT		1
			   FROM			SFin.TransactionDetails	 AS td
			   INNER JOIN	SFin.InvoiceRequestItems AS iri ON (iri.ID = td.InvoiceRequestItemId)
			   WHERE		(iri.InvoiceRequestId = ir.ID)
		   )
					)
	   GROUP BY		ir.ID,
					ir.RowStatus,
					ir.RowVersion,
					ir.Guid,
					ir.Notes,
					ir.CreatedDateTimeUTC,
					i.Guid,
					i.FullName,
					j.Guid,
					j.Number,
					j.FinanceAccountID,
					ActT.Name,
					Acc.Name,
					j.BillingInstruction,
					FinAcc.BillingInstruction;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SFin].[tvf_MyInvoicing]
--
GO
CREATE OR ALTER FUNCTION [SFin].[tvf_MyInvoicing]
	(
		@UserId INT
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT
		t.ID,
		t.RowStatus,
		t.RowVersion,
		t.Guid,
		t.Date,
		t.Number,
		a.Name AS Account,
		td.Gross,
		CASE
				WHEN DATEPART(MONTH,
					t.Date
					) = DATEPART(MONTH,
					GETDATE()
					) THEN
					1
				ELSE
				0
		END	   AS IsCurrentMonth
FROM
		SFin.Transactions AS t
JOIN
		SFin.TransactionDetails AS td ON (td.TransactionID = t.ID)
JOIN
		SFin.TransactionTypes AS tt ON (tt.ID = t.TransactionTypeID)
JOIN
		SJob.Activities AS act ON (act.ID = td.ActivityID)
JOIN
		SJob.Milestones AS m ON (m.ID = td.MilestoneID)
JOIN
		SJob.Jobs AS j ON (j.ID = m.JobId)
				OR (j.ID = t.JobId)
JOIN
		SCrm.Accounts AS a ON (a.ID = t.AccountID)
WHERE
		(t.RowStatus NOT IN (0, 254))
		AND (td.RowStatus NOT IN (0, 254))
		AND (t.ID > 0)
		AND (DATEPART(MONTH,
		t.Date
		) >= (DATEPART(MONTH,
		GETDATE()
		) - 1
		)
		)
		AND (t.SurveyorUserId = @UserId)
		AND (EXISTS
		(
			SELECT
					1
			FROM
					SCore.ObjectSecurityForUser_CanRead(t.Guid, @UserId) oscr
		)
		)
		AND (EXISTS
		(
			SELECT
					1
			FROM
					SCore.ObjectSecurityForUser_CanRead(a.Guid, @UserId) oscr
		)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

