--
-- Create or alter view [SJob].[JobFinance]
--
GO
CREATE OR ALTER VIEW [SJob].[JobFinance]
       --WITH SCHEMABINDING
AS 
SELECT	j.ID,
		TransactionTotals.Net AS InvoicedValue,
		CONVERT(DECIMAL(9, 2), ROUND(j.AgreedFee - TransactionTotals.Net, 2)) AS OutstandingFee
FROM	SJob.Jobs j
OUTER APPLY	
(
	SELECT	SUM(tc.Net * CASE WHEN tt.IsNegated = 1 THEN -1 ELSE 1 END) AS Net
	FROM	SFin.Transactions t
	JOIN	SFin.TransactionTypes tt ON (tt.ID = t.TransactionTypeID)
	JOIN	SFin.TransactionCalculations tc ON (t.ID = tc.ID)
	WHERE	(t.RowStatus NOT IN (0, 254))
		AND	(t.JobID = j.ID)
		AND	(tt.IsBank = 0)
) AS TransactionTotals
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_TeamPciIssuedNotInvoiced]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_TeamPciIssuedNotInvoiced]
	(
		@UserId INT
	)
RETURNS TABLE
         --WITH SCHEMABINDING
AS
RETURN	SELECT	j.ID,
				j.RowStatus,
				j.RowVersion,
				j.Guid,
				j.Number,
				j.JobDescription,
				j.JobTypeID,
				client.Name AS Client,
				jt.Name		AS JobTypeName,
				i.Guid		AS SurveyorGuid,
				i.FullName	AS SurveyorName,
				PCI.CompletedDateTimeUTC,
				jf.OutstandingFee,
				js.IsSubjectToNDA
	   FROM		SJob.Jobs		 AS j
	   JOIN		SJob.JobStatus AS js ON (js.ID = j.ID)
	   JOIN		SJob.JobFinance	 AS jf ON (jf.ID = j.ID)
	   JOIN		SJob.JobTypes	 AS jt ON (j.JobTypeID = jt.ID)
	   JOIN		SCore.Identities AS i ON (j.SurveyorID = i.ID)
	   JOIN		SCrm.Accounts	 AS client ON (client.ID = j.ClientAccountID)
	   CROSS APPLY
				(
					SELECT	m.CompletedDateTimeUTC
					FROM	SJob.Milestones		AS m
					JOIN	SJob.MilestoneTypes AS mt ON (mt.ID = m.MilestoneTypeID)
					WHERE	(m.JobID	  = j.ID)
						AND (m.RowStatus NOT IN (0, 254))
						AND (mt.Code	  = N'PCI')
						AND (m.IsComplete = 1)
						AND (NOT EXISTS
						(
							SELECT	1
							FROM	SJob.Milestones AS m1
							WHERE	(m1.JobID				 = j.ID)
								AND (m1.MilestoneTypeID		 = m.MilestoneTypeID)
								AND (m1.RowStatus NOT IN (0, 254))
								AND (m1.CompletedDateTimeUTC < m.CompletedDateTimeUTC)
						)
							)
				)				 AS PCI
	   CROSS APPLY
					(
						SELECT	ou1.OrgNode
						FROM	SCore.OrganisationalUnits AS ou1
						JOIN	SCore.Identities		  AS i1 ON (i1.OriganisationalUnitId = ou1.ID)
						WHERE	(i1.ID = @UserId)
					) AS CurrentUser
	   WHERE	(j.RowStatus NOT IN (0, 254))
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
				)
			AND (j.IsActive		   = 1)
			AND (j.IsPendingCompletion = 0)
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.OrganisationalUnits AS ou2
			   WHERE	(ou2.ID											  = i.OriganisationalUnitId)
					AND (ou2.OrgNode.IsDescendantOf (CurrentUser.OrgNode) = 1)
		   )
					)
			AND (NOT EXISTS
		   (
			   SELECT	1
			   FROM		SFin.Transactions AS trn
			   WHERE	(trn.RowStatus NOT IN (0, 254))
					AND (trn.JobID = j.ID)
		   )
				)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_TeamCommencedNotInvoiced]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_TeamCommencedNotInvoiced]
	(
		@UserId INT
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT	j.ID,
				j.RowStatus,
				j.RowVersion,
				j.Guid,
				j.Number,
				j.JobDescription,
				j.JobTypeID,
				client.Name AS Client,
				jt.Name		AS JobTypeName,
				i.Guid		AS SurveyorGuid,
				i.FullName	AS SurveyorName,
				SiteWork.StartDateTimeUTC,
				jf.OutstandingFee,
				js.IsSubjectToNDA
	   FROM		SJob.Jobs		 AS j
	   JOIN		SJob.JobStatus AS js ON (js.ID = j.ID)
	   JOIN		SJob.JobFinance	 AS jf ON (jf.ID = j.ID)
	   JOIN		SJob.JobTypes	 AS jt ON (j.JobTypeID = jt.ID)
	   JOIN		SCore.Identities AS i ON (j.SurveyorID = i.ID)
	   JOIN		SCrm.Accounts	 AS client ON (client.ID = j.ClientAccountID)
	   CROSS APPLY
				(
					SELECT	m.StartDateTimeUTC
					FROM	SJob.Milestones		AS m
					WHERE	(m.JobID = j.ID)
						AND (EXISTS 
								(
									SELECT	1
									FROM	SJob.MilestoneTypes AS mt 	
									WHERE	(mt.Code = N'SITEWORK')
										AND	(mt.ID = m.MilestoneTypeID)
								)
							)
						AND (m.StartDateTimeUTC IS NOT NULL)
						AND (m.RowStatus NOT IN (0, 254))
						AND (NOT EXISTS
						(
									SELECT	1
									FROM	SJob.Activities		AS m1
									JOIN	SJob.ActivityTypes	AS aty on (aty.ID = m1.ActivityTypeID)
									JOIN	SJob.ActivityStatus as ast on (ast.ID = m1.ActivityStatusID)
									WHERE	(m1.RowStatus NOT IN (0, 254))
										AND	(m1.JobId = j.Id)
										AND	(aty.IsCommencementTrigger = 1)
										AND	(ast.Name = N'Complete')
								)
							)
				)				 AS SiteWork
	   CROSS APPLY
				(
					SELECT	ou1.OrgNode
					FROM	SCore.OrganisationalUnits AS ou1
					JOIN	SCore.Identities		  AS i1 ON (i1.OriganisationalUnitId = ou1.ID)
					WHERE	(i1.ID = @UserId)
				) AS CurrentUser
	   WHERE	(j.RowStatus NOT IN (0, 254))
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.ObjectSecurityForUser_CanRead (	j.Guid,
																@UserId
															) AS oscr
		   )
				)
			AND (j.IsActive		   = 1)
			AND (j.IsPendingCompletion = 0)
			AND (NOT EXISTS
		   (
			   SELECT	1
			   FROM		SFin.Transactions AS trn
			   WHERE	(trn.RowStatus NOT IN (0, 254))
					AND (trn.JobID = j.ID)
		   )
				)
			AND (EXISTS
		   (
			   SELECT	1
			   FROM		SCore.OrganisationalUnits AS ou2
			   WHERE	(ou2.ID											  = i.OriganisationalUnitId)
					AND (ou2.OrgNode.IsDescendantOf (CurrentUser.OrgNode) = 1)
		   )
				);



GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

