-- Create or alter function [SJob].[tvf_JobActivity]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_JobActivity] 
(
    @UserId INT,
    @ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
            --WITH SCHEMABINDING
AS
RETURN 
SELECT  a.ID,
        a.RowStatus, 
        a.RowVersion,
        a.Guid,
        a.Title,
        a.[Date] AS [Start],
        a.EndDate AS [End],
        s.Name AS [Status],
        t.Name AS [Type],
		i.Guid SurveyorGuid,
		i.FullName AS SurveyorName,
		ActionCount.Total AS TotalActions,
		ISNULL(ActionCount.Outstanding, 0) AS OutstandingActions,
		CONVERT(NVARCHAR(30), ActionCount.Total) + N' | ' + CONVERT(NVARCHAR(30), ISNULL(ActionCount.Outstanding, 0)) AS Actions,
		CONVERT(NVARCHAR(20), CASE WHEN (EXISTS (SELECT 1 FROM SFin.InvoiceRequestItems iri WHERE (iri.ActivityId = a.ID) AND (iri.RowStatus NOT IN (0, 254)))) THEN 1 ELSE 0 END) + N' | '
		+ CONVERT(NVARCHAR(20), CASE WHEN (EXISTS (SELECT 1 FROM SFin.TransactionDetails td WHERE (td.ActivityId = a.ID) AND (td.RowStatus NOT IN (0, 254)))) THEN 1 ELSE 0 END) AS RequestedInvoiced,
		j.FinanceAccountID, -- NEW [CBLD-535]
		CASE
			WHEN t.IsBillable = 0 THEN 'No' ELSE 'Yes' -- [CBLD-534] => Checking if an activity isbi
		END AS IsBillable
FROM    SJob.Activities a
JOIN	SJob.Jobs AS j ON (a.JobID = j.ID) --NEW [CBLD-535]
JOIN    SJob.ActivityStatus s ON (s.Id = a.ActivityStatusID)
JOIN    SJob.ActivityTypes t ON (t.Id = a.ActivityTypeID)
JOIN    SCore.Identities i ON (a.SurveyorID = i.ID)
OUTER APPLY 
(
	SELECT	COUNT(1) AS Total,
			SUM(CASE WHEN act.IsComplete = 0 THEN 1 ELSE 0 END) AS Outstanding
	FROM	SJob.Actions act
	WHERE	(act.RowStatus NOT IN (0, 254))
		AND	(act.ActivityID = a.ID)
) AS ActionCount
WHERE   (a.RowStatus  NOT IN (0, 254))
    AND	(EXISTS
			(
				SELECT	1
				FROM	SCore.ObjectSecurityForUser_CanRead (a.guid, @UserId) oscr
			)
		)
	AND	(
			(EXISTS
				(
					SELECT	1
					FROM	SJob.Jobs j 
					WHERE	 (j.Guid = @ParentGuid)
						AND	(j.RowStatus NOT IN (0, 254))
						AND (j.Id = a.JobID)
				)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_Jobs_DataPills]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Jobs_DataPills]
  (
    @Guid                      UNIQUEIDENTIFIER,
    @AppFormReceived           BIT,
    @ClientAppointmentReceived BIT,
    @ClientAccountGuid         UNIQUEIDENTIFIER,
    @AgentAccountGuid          UNIQUEIDENTIFIER,
	@FinanceAccountGuid		   UNIQUEIDENTIFIER, 
    @JobCompleted              DATETIME2,
    @JobCancelled              DATETIME2,
    @JobDormant                DATETIME2,
    @JobStarted                DATETIME2,
	@OrganisationalUnitGuid    UNIQUEIDENTIFIER, 
	@IsNDA					   BIT,
	@JobTypeGuid			   UNIQUEIDENTIFIER,
	@CannotBeInvoiced		   BIT,
	@CannotBeInvoicedReason    NVARCHAR(MAX),
	@ContractGuid			   UNIQUEIDENTIFIER,
	@AgentContractGuid         UNIQUEIDENTIFIER,
	@ProjectGuid			   UNIQUEIDENTIFIER
  )
RETURNS @DataPills TABLE
  (
    [ID]        [INT]        IDENTITY (1, 1) NOT NULL,
    [Label]     NVARCHAR(50) NOT NULL,
    [Class]     NVARCHAR(50) NOT NULL,
    [SortOrder] INT          NOT NULL
  )
AS
  BEGIN
    DECLARE @JobID INT
	DECLARE	@IsSubjectToNDA BIT 

    SELECT
            @JobID = ID
    FROM
            SJob.Jobs
    WHERE
            (Guid = @Guid)




	SELECT	@IsSubjectToNDA = p.IsSubjectToNDA
	FROM	SSop.Projects AS p
	WHERE	(p.Guid = @ProjectGuid)
  
  --CBLD-680
  IF(@IsSubjectToNDA = 1)
	BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'NDA',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
    END

	

    -- Complete Job
    IF (@JobCompleted IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Complete',	-- Label - nvarchar(50)
                  N'bg-success',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END

    -- Cancelled Job
    IF (@JobCancelled IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Cancelled',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END


    -- Dormant Job
    IF (@JobDormant IS NOT NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Dormant',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END

    -- Started Job
    IF (@JobStarted IS NOT NULL)
      AND
      (@JobCompleted IS NULL)
      AND
      (@JobCancelled IS NULL)
      AND
      (@JobDormant IS NULL)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Job Started',	-- Label - nvarchar(50)
                  N'bg-info',	-- Class - nvarchar(50)
                  2		-- SortOrder - int
                )
      END

    -- Client Account on hold
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SCrm.Accounts a
          JOIN
                  SCrm.AccountStatus st ON (st.ID = a.AccountStatusID)
          WHERE
                  (a.Guid = @ClientAccountGuid)
                  AND (st.IsHold = 1)
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Client Account Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  3		-- SortOrder - int
                )
      END

    -- Agent account on hold
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SCrm.Accounts a
          JOIN
                  SCrm.AccountStatus st ON (st.ID = a.AccountStatusID)
          WHERE
                  (a.Guid = @AgentAccountGuid)
                  AND (st.IsHold = 1)
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Agent Account Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  3		-- SortOrder - int
                )
      END
	  -- Finance Account On Credit Hold
	  IF (EXISTS
			(
				SELECT 
						1
				FROM 
						SCrm.Accounts Ac
				WHERE Ac.Guid = @FinanceAccountGuid AND Ac.AccountStatusID = 4
			)	
		)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Credit Hold',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  1		-- SortOrder - int
                )
      END


    -- Outstanding Fees
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SFin.Transactions t
          JOIN
                  SFin.TransactionCalculations tc ON (tc.ID = t.ID)
          JOIN
                  SFin.TransactionTypes tt ON (tt.ID = t.TransactionTypeID)
          WHERE
                  (t.JobID = @JobID)
                  AND (tc.RealOutstanding <> 0)
                  AND (tt.IsBank = 0)
                  AND (tc.DueDate < GETDATE())
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'Overdue Invoices',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  3		-- SortOrder - int
                )
      END


    -- App Form not received
    IF (@AppFormReceived = 0)
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'App Form Not Received',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  4		-- SortOrder - int
                )
      END

	  --Outstanding Actions
	  	  IF(EXISTS
		(
			SELECT 
				1
			FROM SJob.Actions AS a
			WHERE a.RowStatus NOT IN (0, 254)
			AND a.ActionStatusId <> 1
			  AND (
					EXISTS (
						SELECT 1
						FROM SJob.Jobs AS j
						WHERE j.Guid = @Guid
						  AND j.ID = a.JobID
			 
					)
				 OR EXISTS (
						SELECT 1
						FROM SJob.Milestones AS m
						JOIN SJob.Jobs AS jm ON (jm.ID = m.JobID)
						WHERE jm.Guid = @Guid
						  AND a.MilestoneID = m.ID
						  AND m.RowStatus NOT IN (0, 254)
					)
				 OR EXISTS (
						SELECT 1
						FROM SJob.Activities AS act
						WHERE a.ActivityID = act.ID
						  AND act.RowStatus NOT IN (0, 254)
						  AND (
								EXISTS (
									SELECT 1
									FROM SJob.Jobs AS jact
									WHERE jact.Guid = @Guid
									  AND jact.ID = act.JobID
								)
							 OR EXISTS (
									SELECT 1
									FROM SJob.Milestones AS am
									JOIN SJob.Jobs AS amj ON (amj.ID = am.JobID)
									WHERE amj.Guid = @Guid
									  AND act.MilestoneID = am.ID
									  AND am.RowStatus NOT IN (0, 254)
								)
							)
					)
	
			)
		)
	  )
	  BEGIN
		INSERT @DataPills
		(Label,
		 Class,
		 SortOrder	
		)
		VALUES
		(
		 N'Outstanding Actions',	-- Label - nvarchar(50)
                  N'bg-warning',	-- Class - nvarchar(50)
                  4		-- SortOrder - int
		)
	  END


    -- No Written Appointment
    /*IF (EXISTS 
  			(
  				SELECT	1
  				FROM	SJob.Milestones m 
  				JOIN	SJob.MilestoneTypes mt ON (mt.ID = m.MilestoneTypeID)
  				WHERE	(m.JobID = @JobID)
  					AND	(mt.Code = N'WAR')
  					AND	(m.CompletedDateTimeUTC IS NULL)
  					AND	(m.IsNotApplicable = 0)
  			)
  		)
  	BEGIN 
  		INSERT @DataPills
  			(
  				Label, Class, SortOrder
  			)
  		VALUES(
  				  N'No Written Appointment',	-- Label - nvarchar(50)
  				  N'bg-danger',	-- Class - nvarchar(50)
  				  5		-- SortOrder - int
  			  )
  	END*/


	--Create a table of org units - bccs jobs should not show org i
	DECLARE @OrgTypes TABLE (OrganisationalUnitID UNIQUEIDENTIFIER);
	INSERT INTO @OrgTypes (OrganisationalUnitID)
	VALUES ('F233BB03-3181-49AE-B331-39C58F328457'); --BCCS

	-- No Client Appointment Received
    IF (@ClientAppointmentReceived = 0 
		AND  @OrganisationalUnitGuid NOT IN (SELECT OrganisationalUnitID FROM @OrgTypes) 
		AND @JobTypeGuid  IN ('3B2BB359-D4DA-417E-8D0D-78C82F0EE043', 'AFFB3DA2-EDD8-42A5-A481-8E4AA5A73EC1', '57832995-708D-4B9C-8172-07BD94A3EBCA')) -- CDM-PD, CDM-CON, CDM-PRE
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'No Client Appointment Received',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  5		-- SortOrder - int
                )
      END

    -- F10 Expired
    IF (EXISTS
      (
          SELECT
                  1
          FROM
                  SJob.Milestones m
          JOIN
                  SJob.MilestoneTypes mt ON (mt.ID = m.MilestoneTypeID)
          WHERE
                  (m.JobID = @JobID)
                  AND (mt.Code = N'F10')
                  AND (m.CompletedDateTimeUTC IS NULL)
                  AND (m.IsNotApplicable = 0)
                  AND (
                          (CONVERT(DATE, ISNULL(m.DueDateTimeUTC, GETUTCDATE())) < CONVERT(DATE, GETUTCDATE()))
                          OR (CONVERT(DATE, ISNULL(m.ScheduledDateTimeUTC, GETUTCDATE())) < CONVERT(DATE, GETUTCDATE()))
                  )
      )
      )
      BEGIN
        INSERT @DataPills
              (
                Label,
                Class,
                SortOrder
              )
        VALUES
                (
                  N'F10 Expired',	-- Label - nvarchar(50)
                  N'bg-danger',	-- Class - nvarchar(50)
                  6		-- SortOrder - int
                )
      END

	  -- MileStones Past Deadline Date
	  IF (EXISTS
			(
				SELECT	1
				FROM	SJob.Milestones m
				WHERE	(m.JobId = @JobID)
					AND	(m.CompletedDateTimeUTC IS NULL)
					AND	(ISNULL(m.DueDateTimeUTC, GETUTCDATE()) < GETUTCDATE())
			)
		)
		BEGIN 
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'Overdue Milestones.',	-- Label - nvarchar(50)
						N'bg-warning',	-- Class - nvarchar(50)
						6		-- SortOrder - int
					)
		END


	  -- Incomplete historic activities 
	  IF	(EXISTS
				(
					SELECT	1
					FROM	SJob.Activities a
					WHERE	(a.JobID = @JobID)
						AND	(a.EndDate < GETUTCDATE())
						AND	(EXISTS
								(
									SELECT	1
									FROM	SJob.ActivityStatus ast
									WHERE	(ast.ID = a.ActivityStatusID)
										AND	(ast.IsCompleteStatus = 0) 
								)
							)
				)	
			)
		BEGIN 
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'Incomplete Activities.',	-- Label - nvarchar(50)
						N'bg-warning',	-- Class - nvarchar(50)
						6		-- SortOrder - int
					)
		END

		IF(@CannotBeInvoiced = 1)
		BEGIN
			INSERT @DataPills
				  (
					Label,
					Class,
					SortOrder
				  )
			VALUES
					(
					  N'Cannot Be Invoiced',	-- Label - nvarchar(50)
					  N'bg-danger',	-- Class - nvarchar(50)
					  7		-- SortOrder - int
					)
		  END


		  IF(@ContractGuid <> '00000000-0000-0000-0000-000000000000' OR @AgentContractGuid <> '00000000-0000-0000-0000-000000000000')
		  BEGIN
			INSERT @DataPills
				  (
					Label,
					Class,
					SortOrder
				  )
			VALUES
					(
					  N'Contract In Place',	-- Label - nvarchar(50)
					  N'bg-warning',	-- Class - nvarchar(50)
					  7		-- SortOrder - int
					)

			
			--Get the EndDate + NextReviewDate when either contract field is set
			DECLARE @EndDate DATE,
					@NextReviewDate DATE;

			
			IF(@ContractGuid <> '00000000-0000-0000-0000-000000000000')
			BEGIN
				SELECT @EndDate = EndDate, 
					   @NextReviewDate = NextReviewDate
				FROM SSop.Contracts
				WHERE (Guid = @ContractGuid);

			END
			ELSE IF(@AgentContractGuid <> '00000000-0000-0000-0000-000000000000')
			BEGIN
				SELECT @EndDate = EndDate, 
					   @NextReviewDate = NextReviewDate
				FROM SSop.Contracts
				WHERE (Guid = @AgentContractGuid);
			END;

			--Check how many days are left before the contract expires.
			IF DATEDIFF(DAY, GETDATE(), @EndDate) <= 30
			BEGIN
				INSERT @DataPills
					  (
						Label,
						Class,
						SortOrder
					  )
				VALUES
						(
						  N'Contract Ending In ' + CONVERT(NVARCHAR(10), DATEDIFF(DAY, GETDATE(), @EndDate)) + N' Days',	-- Label - nvarchar(50)
						  N'bg-danger',	-- Class - nvarchar(50)
						  8		-- SortOrder - int
						)
			END

			--Check how many days before the contract needs reviewing. 
			IF DATEDIFF(DAY, GETDATE(), @NextReviewDate) <= 30
			BEGIN
				INSERT @DataPills
						  (
							Label,
							Class,
							SortOrder
						  )
				VALUES
						(
						  N'Contract Needs Reviewing By ' + CONVERT(NVARCHAR(10), @NextReviewDate, 23) ,	-- Label - nvarchar(50)
						  N'bg-danger',	-- Class - nvarchar(50)
						  9		-- SortOrder - int
						)
			END;
		  END

    RETURN
  END


GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_JobMilestoneActions]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_JobMilestoneActions]
	(
		@UserId INT,
		@ParentGuid UNIQUEIDENTIFIER
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT		a.ID,
					a.RowStatus,
					a.RowVersion,
					a.Guid,
					a.Notes,
					a.IsComplete,
					a.CreatedDateTimeUTC,
					i.FullName AS CreatedBy,
					ast.Name as ActionStatus
	   FROM			SJob.Actions				  AS a
	   JOIN			SJob.ActionStatus ast		on (a.ActionStatusId = ast.Id)
	   JOIN			SCore.Identities			  AS i ON (i.ID = a.CreatedByUserID)
	   JOIN			SJob.Milestones				  AS m ON (m.ID = a.MilestoneID)
	   WHERE		(a.RowStatus NOT IN (0, 254))
				AND	(EXISTS
			(
					SELECT
							1
					FROM
							SCore.ObjectSecurityForUser_CanRead(a.Guid, @UserId) oscr
			)
		)
				AND
				  (
					  (EXISTS
		   (
			   SELECT	1
			   FROM		SJob.Milestones AS m
			   WHERE	(m.Guid		   = @ParentGuid)
					AND (a.MilestoneID = m.ID)
					AND (m.RowStatus NOT IN (0, 254))
		   )
					  )
				   OR (EXISTS
		   (
			   SELECT	1
			   FROM		SJob.Activities AS act
			   JOIN		SJob.Milestones AS m ON (m.ID = act.MilestoneID)
			   WHERE	(m.Guid		  = @ParentGuid)
					AND (a.ActivityID = act.ID)
					AND (act.RowStatus NOT IN (0, 254))
		   )
					  )
				  );
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_JobActions]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_JobActions]
	(
		@UserId INT,
		@ParentGuid UNIQUEIDENTIFIER
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT		a.ID,
					a.RowStatus,
					a.RowVersion,
					a.Guid,
					a.Notes,
					a.IsComplete,
					a.CreatedDateTimeUTC,
					i.FullName AS CreatedBy,
					ast.Name as ActionStatus
	   FROM			SJob.Actions				  AS a
	   join			SJob.ActionStatus ast		on (a.ActionStatusId = ast.Id)
	   JOIN			SCore.Identities			  AS i ON (i.ID = a.CreatedByUserID)
	   WHERE		(a.RowStatus NOT IN (0, 254))
				AND	(EXISTS
			(
					SELECT
							1
					FROM
							SCore.ObjectSecurityForUser_CanRead(a.Guid, @UserId) oscr
			)
		)
				AND
				  (
					  (EXISTS
		   (
			   SELECT	1
			   FROM		SJob.Jobs AS j
			   WHERE	(j.Guid = @ParentGuid)
					AND (j.ID	= a.JobID)
		   )
					  )
				   OR (EXISTS
		   (
			   SELECT	1
			   FROM		SJob.Milestones AS m
			   JOIN		SJob.Jobs		AS jm ON (jm.ID = m.JobID)
			   WHERE	(jm.Guid	   = @ParentGuid)
					AND (a.MilestoneID = m.ID)
					AND (m.RowStatus NOT IN (0, 254))
		   )
					  )
				   OR (EXISTS
		   (
			   SELECT	1
			   FROM		SJob.Activities AS act
			   WHERE	(a.ActivityID = act.ID)
					AND (act.RowStatus NOT IN (0, 254))
					AND
					  (
						  (EXISTS
				   (
					   SELECT	1
					   FROM		SJob.Jobs AS jact
					   WHERE	(jact.Guid = @ParentGuid)
							AND (jact.ID   = act.JobID)
				   )
						  )
					   OR (EXISTS
				   (
					   SELECT	1
					   FROM		SJob.Milestones AS am
					   JOIN		SJob.Jobs		AS amj ON (amj.ID = am.JobID)
					   WHERE	(amj.Guid		 = @ParentGuid)
							AND (act.MilestoneID = am.ID)
							AND (am.RowStatus NOT IN (0, 254))
				   )
						  )
					  )
		   )
					  )
				  );

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[tvf_JobActivityActions]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_JobActivityActions]
	(
		@UserId INT,
		@ParentGuid UNIQUEIDENTIFIER
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
RETURN SELECT		a.ID,
					a.RowStatus,
					a.RowVersion,
					a.Guid,
					a.Notes,
					a.IsComplete,
					a.CreatedDateTimeUTC,
					i.FullName AS CreatedBy,
					ast.Name as ActionStatus
	   FROM			SJob.Actions				  AS a
	   JOIN			SJob.ActionStatus ast		on (a.ActionStatusId = ast.Id)
	   JOIN			SCore.Identities			  AS i ON (i.ID = a.CreatedByUserID)
	   JOIN			SJob.Activities				  AS ac ON (ac.ID = a.ActivityID)
	   WHERE		(a.RowStatus NOT IN (0, 254))
				AND (ac.Guid	= @ParentGuid)
AND	(EXISTS
			(
					SELECT
							1
					FROM
							SCore.ObjectSecurityForUser_CanRead(a.Guid, @UserId) oscr
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
