--
-- Create or alter function [SJob].[tvf_Actions_UserAssigned]
--
GO
CREATE OR ALTER FUNCTION [SJob].[tvf_Actions_UserAssigned]
	(
		@UserId		INT
	)
RETURNS TABLE
   --WITH SCHEMABINDING
AS
	RETURN SELECT
			a.ID,
			a.RowStatus,
			a.RowVersion,
			a.Guid,
			a.Notes,
			a.IsComplete,
			a.CreatedDateTimeUTC,
			i.FullName  AS CreatedBy,
			i1.FullName AS Assignee,
			ap.Name		AS Priority,
			at.Name		AS Type,
			[as].Name   AS Status
	FROM
			SJob.Actions as a
	JOIN
			SCore.Identities as i ON (i.ID = a.CreatedByUserID)
	JOIN
			SCore.Identities i1 ON (a.AssigneeUserId = i1.ID)
	JOIN
			SJob.ActionPriorities ap ON (a.ActionPriorityId = ap.ID)
	JOIN
