					p.Guid AS SourcePropertyGuid,
					tp.Guid AS DependantPropertyGuid
	   FROM			SCore.EntityPropertyDependants AS epd
	   JOIN			SCore.EntityProperties					AS p ON (p.ID = epd.ParentEntityPropertyID)
