--
-- Create or alter function [SSop].[Tvf_GetEnquiryStatuses]
--
GO
CREATE OR ALTER FUNCTION [SSop].[Tvf_GetEnquiryStatuses](@id INT)
RETURNS TABLE
    --WITH SCHEMABINDING
AS
RETURN
SELECT
    QuotingStatus =
        CASE
            ----------------------------------------------------------------------
            -- HIGHEST PRIORITY: Dead or Declined at Enquiry level
            ----------------------------------------------------------------------
            WHEN e.DeadDate IS NOT NULL THEN N'Dead'
            WHEN e.DeclinedToQuoteDate IS NOT NULL THEN N'Declined'

            ----------------------------------------------------------------------
            -- NEW: No services exist (fallback only if no final status above)
            ----------------------------------------------------------------------
            WHEN NOT EXISTS (
                SELECT 1
                FROM SSop.EnquiryServices es
                WHERE es.EnquiryId = e.ID AND es.RowStatus NOT IN (0, 254)
            ) THEN N'New'

            ----------------------------------------------------------------------
            -- COMPLETE: All services either Rejected OR Accepted+Job created
            ----------------------------------------------------------------------
            WHEN NOT EXISTS (
                SELECT 1
                FROM SSop.EnquiryServices es
                WHERE es.EnquiryId = e.ID AND es.RowStatus NOT IN (0, 254)
                AND NOT (
                    EXISTS (
                        SELECT 1
                        FROM SSop.Quotes q
                        JOIN SSop.QuoteItems qi ON qi.QuoteId = q.ID
                        WHERE q.EnquiryServiceID = es.ID
                        AND q.DateAccepted IS NOT NULL
                        AND qi.RowStatus NOT IN (0, 254)
                        AND qi.CreatedJobId > 0
                    )
                    OR EXISTS (
                        SELECT 1
                        FROM SSop.Quotes q
                        WHERE q.EnquiryServiceID = es.ID AND q.DateRejected IS NOT NULL
                    )
                )
            ) THEN N'Complete'

            ----------------------------------------------------------------------
            -- PART COMPLETE: Mix of accepted/rejected and incomplete services
            ----------------------------------------------------------------------
            WHEN EXISTS (
                SELECT 1
                FROM SSop.EnquiryServices es
                JOIN SSop.Quotes q ON es.ID = q.EnquiryServiceID
                JOIN SSop.QuoteItems qi ON q.ID = qi.QuoteId
                WHERE es.EnquiryId = e.ID
                  AND es.RowStatus NOT IN (0,254)
                  AND q.DateAccepted IS NOT NULL
                  AND qi.RowStatus NOT IN (0,254)
                  AND qi.CreatedJobId > 0
            )
            AND EXISTS (
                SELECT 1
                FROM SSop.EnquiryServices es
                WHERE es.EnquiryId = e.ID
                  AND es.RowStatus NOT IN (0,254)
                  AND NOT (
                        EXISTS (
                            SELECT 1
                            FROM SSop.Quotes q
                            JOIN SSop.QuoteItems qi ON q.ID = qi.QuoteId
                            WHERE q.EnquiryServiceID = es.ID
                            AND q.DateAccepted IS NOT NULL
                            AND qi.RowStatus NOT IN (0, 254)
                            AND qi.CreatedJobId > 0
                        )
                        OR EXISTS (
                            SELECT 1 FROM SSop.Quotes q
                            WHERE q.EnquiryServiceID = es.ID AND q.DateRejected IS NOT NULL
                        )
                  )
            ) THEN N'Part Complete'

            ----------------------------------------------------------------------
            -- REJECTED: All relevant quotes are explicitly rejected, none accepted or pending
            ----------------------------------------------------------------------            
			WHEN EXISTS (
				SELECT 1
				FROM SSop.Quotes q
				JOIN SSop.EnquiryServices es ON es.ID = q.EnquiryServiceID
				WHERE es.EnquiryId = e.ID
				  AND es.RowStatus NOT IN (0, 254)
			)
			AND NOT EXISTS (
				SELECT 1
				FROM SSop.Quotes q
				JOIN SSop.EnquiryServices es ON es.ID = q.EnquiryServiceID
				WHERE es.EnquiryId = e.ID
				  AND es.RowStatus NOT IN (0, 254)
				  AND (
					  q.DateAccepted IS NOT NULL
				   OR q.DateDeclinedToQuote IS NOT NULL
				   OR q.DateRejected IS NULL -- <-- A quote exists that is not explicitly rejected
				   OR q.DeadDate IS NOT NULL
				   OR q.ExpiryDate >= GETUTCDATE()
				  )
			)
			THEN N'Rejected'

            ----------------------------------------------------------------------
            -- SENT: All services have quotes sent AND no accepted/rejected/declined
            ----------------------------------------------------------------------
            WHEN NOT EXISTS (
                SELECT 1
                FROM SSop.EnquiryServices es
                WHERE es.EnquiryId = e.ID
                  AND es.RowStatus NOT IN (0, 254)
                  AND NOT EXISTS (
                      SELECT 1 FROM SSop.Quotes q
                      WHERE q.EnquiryServiceID = es.ID AND q.DateSent IS NOT NULL
                  )
            )
            AND NOT EXISTS (
                SELECT 1
                FROM SSop.Quotes q
                JOIN SSop.EnquiryServices es ON q.EnquiryServiceID = es.ID
                WHERE es.EnquiryId = e.ID
                AND es.RowStatus NOT IN (0, 254)
                AND (
                    q.DateAccepted IS NOT NULL OR
                    q.DateRejected IS NOT NULL OR
                    q.DateDeclinedToQuote IS NOT NULL
                )
            ) THEN N'Sent'

            ----------------------------------------------------------------------
            -- PART SENT: Some quotes sent, others missing or incomplete
            ----------------------------------------------------------------------
            WHEN EXISTS (
                SELECT 1
                FROM SSop.EnquiryServices es
                WHERE es.EnquiryId = e.ID AND es.RowStatus NOT IN (0, 254)
                AND (
                    NOT EXISTS (
                        SELECT 1 FROM SSop.Quotes q WHERE q.EnquiryServiceID = es.ID
                    )
                    OR EXISTS (
                        SELECT 1
                        FROM SSop.Quotes q
                        WHERE q.EnquiryServiceID = es.ID
                        AND q.DateSent IS NULL
                        AND q.DateRejected IS NULL
                        AND q.DateDeclinedToQuote IS NULL
                    )
                )
            )
            AND EXISTS (
                SELECT 1
                FROM SSop.Quotes q
                JOIN SSop.EnquiryServices es ON q.EnquiryServiceID = es.ID
                WHERE es.EnquiryId = e.ID AND es.RowStatus NOT IN (0, 254)
                AND q.DateSent IS NOT NULL
            ) THEN N'Part Sent'

            ----------------------------------------------------------------------
            -- ACCEPTED
            ----------------------------------------------------------------------
            WHEN EXISTS (
                SELECT 1
                FROM SSop.Quotes q
                JOIN SSop.EnquiryServices es ON es.ID = q.EnquiryServiceID
                WHERE es.EnquiryId = e.ID
                  AND es.RowStatus NOT IN (0, 254)
                  AND q.DateAccepted IS NOT NULL
            ) THEN N'Accepted'

            ----------------------------------------------------------------------
            -- QUOTING
            ----------------------------------------------------------------------
            WHEN EXISTS (
                SELECT 1
                FROM SSop.Quotes q
                JOIN SSop.EnquiryServices es ON es.ID = q.EnquiryServiceID
                WHERE es.EnquiryId = e.ID
                  AND es.RowStatus NOT IN (0, 254)
            ) THEN N'Quoting'

            ----------------------------------------------------------------------
            -- FALLBACK
            ----------------------------------------------------------------------
            ELSE NULL
        END
FROM SSop.Enquiries e
WHERE e.ID = @id;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Enquiry_CalculatedFields]
--
GO
CREATE OR ALTER VIEW [SSop].[Enquiry_CalculatedFields]
--WITH SCHEMABINDING
AS
SELECT	
	e.ID,
	EnquiryStatus =
		CASE
			-- 1. TVF status is a final status: use it
			WHEN s.QuotingStatus IS NOT NULL 
			     AND s.QuotingStatus NOT IN (N'Sent', N'Part Sent', N'Quoting')
			     THEN s.QuotingStatus

			-- 2. TVF status is transitional AND we have fallback data
			WHEN s.QuotingStatus IN (N'Sent', N'Part Sent', N'Quoting')
				 AND (
					  e.DeadDate IS NOT NULL
				   OR e.DeclinedToQuoteDate IS NOT NULL
				   OR e.QuotingDeadlineDate < GETDATE()
				   OR e.QuotingDeadlineDate < DATEADD(DAY, 2, GETDATE())
				   OR e.ChaseDate2 IS NOT NULL
				   OR e.ChaseDate1 IS NOT NULL
				   OR (
					   e.IsReadyForQuoteReview = 1
					   AND NOT EXISTS (
						  SELECT 1 FROM SSop.EnquiryServices es 
						  JOIN SSop.Quotes q ON es.ID = q.EnquiryServiceID 
						  WHERE es.EnquiryId = e.ID AND q.DateSent IS NOT NULL
					   )
				   )
				 )
			THEN 
			   CASE
				   WHEN e.DeadDate IS NOT NULL THEN N'Dead'
				   WHEN e.DeclinedToQuoteDate IS NOT NULL THEN N'Declined'
				   WHEN e.QuotingDeadlineDate < GETDATE() THEN N'Deadline Missed'
				   WHEN e.QuotingDeadlineDate < DATEADD(DAY, 2, GETDATE()) THEN N'Deadline Approaching'
				   WHEN e.ChaseDate2 IS NOT NULL THEN N'2nd Chase'
				   WHEN e.ChaseDate1 IS NOT NULL THEN N'1st Chase'
				   WHEN e.IsReadyForQuoteReview = 1 
					 AND NOT EXISTS (
						  SELECT 1 FROM SSop.EnquiryServices es 
						  JOIN SSop.Quotes q ON es.ID = q.EnquiryServiceID 
						  WHERE es.EnquiryId = e.ID AND q.DateSent IS NOT NULL
					 ) THEN N'Ready for Quote'
				   ELSE s.QuotingStatus
			   END

			-- 3. No fallback data – return whatever TVF gave us
			WHEN s.QuotingStatus IS NOT NULL THEN s.QuotingStatus

			-- 4. Only if no TVF and no fallback
			ELSE N'New'
		END
FROM	SSop.Enquiries e
OUTER APPLY SSop.tvf_GetEnquiryStatuses(e.Id) as s;

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_EnquiriesForQuoteReview]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiriesForQuoteReview]
(
	@UserId INT
)
RETURNS TABLE
              --WITH SCHEMABINDING
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		e.Number,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN acc.Name <> N'' THEN acc.Name ELSE e.ClientName END AS Account,
		-- New fields
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		ecf.EnquiryStatus,
		org.Name AS OrgUnit,
		e.Date,
		ISNULL(ServiceTypes.Name, N'Multi Discipline') AS Disciplines
FROM    SSop.Enquiries e
JOIN	SCrm.Accounts acc ON (acc.ID = e.ClientAccountID)
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
JOIN	SCore.OrganisationalUnits AS org ON (org.ID = e.OrganisationalUnitID)
OUTER APPLY (
	SELECT	jt.Name
	FROM	SJob.JobTypes AS jt
	WHERE	(EXISTS
				(
					SELECT	1
					FROM 	SSop.EnquiryServices AS es 
					WHERE	(es.JobTypeId = jt.ID)
						AND	(es.EnquiryId = e.ID)
						AND	(es.RowStatus NOT IN (0, 254))
						AND	(NOT EXISTS
								(
									SELECT	1
									FROM	SSop.EnquiryServices es2 
									WHERE	(es2.ID <> es.ID)
										AND	(es2.EnquiryId = es.EnquiryId)
										AND	(es2.RowStatus NOT IN (0, 254))
								)
							)
				)
			)
) AS ServiceTypes
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)
	AND	(e.IsReadyForQuoteReview = 1)
	AND	(EXISTS
			(
				SELECT	1
				FROM	SSop.EnquiryServices es
				WHERE	(es.EnquiryId = e.ID)
					AND	(es.RowStatus NOT IN (0, 254))
					AND	(NOT EXISTS
							(
								SELECT	1
								FROM	SSop.Quotes AS q
								WHERE	(q.EnquiryServiceID = es.ID)
									AND	(q.RowStatus NOT IN (0, 254))
							)
						)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_OpenEnquiries]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_OpenEnquiries]
(
	@UserId INT
)
RETURNS TABLE
     --WITH SCHEMABINDING
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		CASE WHEN e.Revision = 0 THEN e.Number ELSE (e.Number + N' (' + CONVERT(NVARCHAR(2), e.Revision) + N') ') END AS Number,
		e.QuotingDeadlineDate,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		ecf.EnquiryStatus
FROM    SSop.Enquiries e
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)
	AND	(e.DeclinedToQuoteDate IS NULL)
	AND	(EXISTS
			(
				SELECT	1
				FROM	SSop.EnquiryServices es 
				WHERE	(es.EnquiryId = e.ID)
					AND	(es.RowStatus NOT IN (0, 254))
					AND	(es.QuoteId < 0)
			)
		)
	AND	(e.Date > DATEADD(MONTH, -6, GETDATE()))
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_Enquiries]
--
GO
CREATE OR ALTER FUNCTION [SSop].[tvf_Enquiries]
(
	@UserId INT
)
RETURNS TABLE
     --WITH SCHEMABINDING
AS RETURN	
SELECT  e.ID,
        e.RowStatus,
        e.RowVersion,
        e.Guid,
		CASE WHEN e.Revision = 0 THEN e.Number ELSE (e.Number + N' (' + CONVERT(NVARCHAR(2), e.Revision) + N') ') END AS Number,
		e.ExternalReference,
		LEFT(e.DescriptionOfWorks, 200) AS DescriptionOfWorks, 
		CASE WHEN client.Name <> N'' THEN client.Name ELSE e.ClientName END + N' / ' + CASE WHEN agent.Name <> N'' THEN agent.Name ELSE e.AgentName END  AS ClientAgentAccount,
		CASE WHEN uprn.AssetNumber > 0 THEN uprn.FormattedAddressComma ELSE e.PropertyNameNumber + N' ' + e.PropertyAddressLine1 END AS Property,
		uprn.AssetNumber AS UPRN,
		ecf.EnquiryStatus,
		ISNULL(p.IsSubjectToNDA, e.IsSubjectToNDA) AS IsSubjectToNDA,
		CASE WHEN ServiceTypes.Name IS NULL THEN N'Multi Discipline' ELSE ServiceTypes.Name END AS Disciplines,
		org.Name AS OrgUnit,
		e.Date 
FROM    SSop.Enquiries e
JOIN	SSop.Enquiry_CalculatedFields AS ecf ON (ecf.ID = e.ID)
JOIN	SCrm.Accounts client ON (client.ID = e.ClientAccountID)
JOIN	SCrm.Accounts agent ON (agent.ID = e.AgentAccountId)
JOIN	SJob.Assets uprn ON (uprn.ID = e.PropertyId)
JOIN	SSop.Projects AS p ON (p.ID = e.ProjectId)
JOIN	SCore.OrganisationalUnits AS org ON (org.ID = e.OrganisationalUnitID)
OUTER APPLY (
	SELECT	jt.Name
	FROM	SJob.JobTypes AS jt
	WHERE	(EXISTS
				(
					SELECT	1
					FROM 	SSop.EnquiryServices AS es 
					WHERE	(es.JobTypeId = jt.ID)
						AND	(es.EnquiryId = e.ID)
						AND	(es.RowStatus NOT IN (0, 254))
						AND	(NOT EXISTS
								(
									SELECT	1
									FROM	SSop.EnquiryServices es2 
									WHERE	(es2.ID <> es.ID)
										AND	(es2.EnquiryId = es.EnquiryId)
										AND	(es2.RowStatus NOT IN (0, 254))
								)
							)
				)
			)
) AS ServiceTypes
WHERE   (e.RowStatus NOT IN (0, 254))
	AND	(e.ID > 0)
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(e.Guid, @UserId) oscr
			)
		)

GO
